+        publisher.failed(expectedException);
+        verify(subscriber, times(1)).onError(eq(expectedException));
+        subscription.getValue().request(1);
+        publisher.failed(expectedException);
+        verify(subscriber, times(1)).onError(eq(expectedException));
+    }
